/* Navigation Buttons */
.stage-navigation {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-top: 60px;
    padding-top: 30px;
    border-top: 1px solid var(--glass-border);
}

.stage-nav-btn {
    display: inline-flex;
    align-items: center;
    gap: 12px;
    padding: 16px 28px;
    border-radius: 12px;
    font-weight: 600;
    font-size: 1.05rem;
    text-decoration: none;
    transition: all 0.3s ease;
    backdrop-filter: blur(10px);
}

.stage-nav-btn svg {
    transition: transform 0.3s ease;
}

.nav-back {
    background: rgba(255, 255, 255, 0.03);
    color: var(--text-main);
    border: 1px solid var(--glass-border);
}

.nav-back:hover {
    background: rgba(255, 255, 255, 0.08);
    transform: translateX(-4px);
}

.nav-back:hover svg {
    transform: translateX(-4px);
}

.nav-next-green {
    background: rgba(52, 211, 153, 0.1);
    color: var(--neon-green);
    border: 1px solid rgba(52, 211, 153, 0.3);
}

.nav-next-green:hover {
    background: rgba(52, 211, 153, 0.2);
    transform: translateX(4px);
    box-shadow: 0 4px 15px rgba(52, 211, 153, 0.2);
}

.nav-next-purple {
    background: rgba(192, 132, 252, 0.1);
    color: var(--neon-purple);
    border: 1px solid rgba(192, 132, 252, 0.3);
}

.nav-next-purple:hover {
    background: rgba(192, 132, 252, 0.2);
    transform: translateX(4px);
    box-shadow: 0 4px 15px rgba(192, 132, 252, 0.2);
}

.nav-next-orange {
    background: rgba(251, 146, 60, 0.1);
    color: var(--neon-orange);
    border: 1px solid rgba(251, 146, 60, 0.3);
}

.nav-next-orange:hover {
    background: rgba(251, 146, 60, 0.2);
    transform: translateX(4px);
    box-shadow: 0 4px 15px rgba(251, 146, 60, 0.2);
}

.nav-home {
    background: rgba(56, 189, 248, 0.1);
    color: var(--neon-blue);
    border: 1px solid rgba(56, 189, 248, 0.3);
}

.nav-home:hover {
    background: rgba(56, 189, 248, 0.2);
    transform: translateY(-4px);
    box-shadow: 0 4px 15px rgba(56, 189, 248, 0.2);
}

.nav-next-green:hover svg, .nav-next-purple:hover svg, .nav-next-orange:hover svg {
    transform: translateX(4px);
}

}

